export type LocalePatch = {
  navApp: string;
  getApp: { eyebrow: string; title: string; body: string; cta: string; install: string };
  portal: string;
  tagline: string;
  openWebsite: string;
  stageBadge: string;
  nav: { dashboard: string; apply: string; projects: string; contact: string; install: string };
  welcome: string;
  dashboardSubtitle: string;
  quickActions: string;
  stats: { focusAreas: string; pipeline: string; stage: string; stageValue: string };
  cards: {
    apply: { title: string; description: string; cta: string };
    projects: { title: string; description: string; cta: string };
    contact: { title: string; description: string; cta: string };
    install: { title: string; description: string; cta: string };
  };
  notice: string;
  ecosystem: string;
  apply: {
    title: string;
    subtitle: string;
    organizationType: string;
    selectType: string;
    orgTypes: Record<string, string>;
    successTitle: string;
    successBody: string;
  };
  projects: { title: string; subtitle: string; stages: { research: string; concept: string; pilot: string } };
  contact: { title: string; subtitle: string };
  install: {
    title: string;
    subtitle: string;
    ios: { title: string; steps: string[] };
    android: { title: string; steps: string[] };
    desktop: { title: string; steps: string[] };
  };
};

